function fixGridRowHeight(cssCode) {
  const gridTemplateRows = cssCode.match(/grid-template-rows: (.*)/)[1];
  return cssCode.replace(/grid-template-rows: (.*)/, `grid-template-rows: repeat(2, ${gridTemplateRows})`);
}

